#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *A = (int*)malloc(N*sizeof(int));
        int *pos = (int*)malloc((N+2)*sizeof(int)); // 1‑based, extra for sentinel
        for(int i=1;i<=N;i++){
            scanf("%d", &A[i-1]);
            pos[A[i-1]] = i;
        }
        long long ans = 0;
        long long cur = 1; // len for i = N
        ans += cur;
        for(int i=N-1;i>=1;i--){
            if(pos[i] < pos[i+1]) cur = cur + 1;
            else cur = 1;
            ans += cur;
        }
        printf("%lld\n", ans);
        free(A); free(pos);
    }
    return 0;
}

