#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        pos = [0] * (N + 2)
        for i in range(1, N + 1):
            x = int(next(it))
            pos[x] = i
        ans = 0
        cur = 1  # for i = N
        ans += cur
        for i in range(N - 1, 0, -1):
            if pos[i] < pos[i + 1]:
                cur += 1
            else:
                cur = 1
            ans += cur
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

